/**
 * Multer middleware configured with Cloudinary storage.
 * Accepts a single file under the field name "image".
 * Allowed formats: jpeg, png, jpg.
 */
const multer = require('multer');
const { CloudinaryStorage } = require('multer-storage-cloudinary');
const cloudinary = require('../config/cloudinary');

const storage = new CloudinaryStorage({
  cloudinary,
  params: {
    folder: 'wasalny',
    allowed_formats: ['jpeg', 'png', 'jpg'],
    // public_id is auto-generated by Cloudinary if omitted
  },
});

const upload = multer({
  storage,
  limits: { fileSize: 5 * 1024 * 1024 }, // 5 MB max
  fileFilter: (req, file, cb) => {
    const allowed = ['image/jpeg', 'image/png', 'image/jpg'];
    if (allowed.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error('نوع الملف غير مدعوم. استخدم jpeg أو png أو jpg'), false);
    }
  },
});

module.exports = upload;
